CREATE TRIGGER [dbo].[Container_History]ON [dbo].[Container]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.ContainerId IS NOT NULL AND d.ContainerId IS NULL THEN 'I' 		WHEN i.ContainerId IS NOT NULL AND d.ContainerId IS NOT NULL THEN 'U' 		WHEN i.ContainerId IS NULL AND d.ContainerId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.ContainerId = d.ContainerId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_Container([ContainerId], [ContainerTypeId], [InventoryLocationId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [ContainerId], [ContainerTypeId], [InventoryLocationId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_Container([ContainerId], [ContainerTypeId], [InventoryLocationId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [ContainerId], [ContainerTypeId], [InventoryLocationId], [SerialNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND